// Counts a notification audience against a real users array fetched from
// the backend (GET /users) — pass it in from wherever this is called.
function audienceCount(audience, users = []) {
  switch (audience) {
    case "Active Users": return users.filter((u) => u.status === "active").length;
    case "Suspended Users": return users.filter((u) => u.status === "suspended").length;
    case "KYC Verified": return users.filter((u) => u.kyc === "verified").length;
    case "KYC Pending": return users.filter((u) => u.kyc === "pending").length;
    case "Reseller Users": return users.filter((u) => u.accountType === "reseller").length;
    case "API Users": return users.filter((u) => u.accountType === "api").length;
    default: return users.length;
  }
}

