/* ------------------------------------------------------------------ */
function StatusPill({ status }) {
  const map = {
    success: { label: "Successful", bg: "bg-emerald-50", text: "text-emerald-700", dot: "bg-emerald-500" },
    pending: { label: "Pending", bg: "bg-blue-50", text: "text-blue-700", dot: "bg-blue-500" },
    failed: { label: "Failed", bg: "bg-rose-50", text: "text-rose-700", dot: "bg-rose-500" },
    refunded: { label: "Refunded", bg: "bg-purple-50", text: "text-purple-700", dot: "bg-purple-500" },
    processing: { label: "Processing", bg: "bg-sky-50", text: "text-sky-700", dot: "bg-sky-500" },
    approved: { label: "Approved", bg: "bg-indigo-50", text: "text-indigo-700", dot: "bg-indigo-500" },
    paid: { label: "Paid", bg: "bg-emerald-50", text: "text-emerald-700", dot: "bg-emerald-500" },
    rejected: { label: "Rejected", bg: "bg-rose-50", text: "text-rose-700", dot: "bg-rose-500" },
    qualified: { label: "Qualified", bg: "bg-teal-50", text: "text-teal-700", dot: "bg-teal-500" },
    rewarded: { label: "Rewarded", bg: "bg-violet-50", text: "text-violet-700", dot: "bg-violet-500" },
  };
  const s = map[status];
  return (
    <span className={`inline-flex items-center gap-1.5 rounded-full px-2.5 py-1 text-xs font-medium ${s.bg} ${s.text}`}>
      <span className={`h-1.5 w-1.5 rounded-full ${s.dot}`} />
      {s.label}
    </span>
  );
}

function StatCard({ label, value, sub, icon: Icon, accent = BRAND.amber, delay = 0 }) {
  const [charge, setCharge] = useState(0);
  useEffect(() => {
    const t = setTimeout(() => setCharge(100), 80 + delay);
    return () => clearTimeout(t);
  }, [delay]);
  return (
    <div className="relative overflow-hidden rounded-2xl bg-white border border-slate-200/70 shadow-sm p-4 sm:p-5">
      {/* signature "recharge" bar */}
      <div className="absolute top-0 left-0 h-1 w-full bg-slate-100">
        <div
          className="h-1 transition-all duration-1000 ease-out"
          style={{ width: `${charge}%`, background: accent }}
        />
      </div>
      <div className="flex items-start justify-between">
        <div className="min-w-0">
          <p className="text-[11px] font-medium uppercase tracking-wide text-slate-400">{label}</p>
          <p className="mt-1.5 text-xl sm:text-2xl font-semibold text-slate-900 truncate" style={{ fontFamily: "Sora, sans-serif" }}>
            {value}
          </p>
          {sub && <p className="mt-1 text-xs text-slate-500">{sub}</p>}
        </div>
        <div
          className="shrink-0 rounded-xl p-2.5"
          style={{ background: `${accent}1A`, color: accent }}
        >
          <Icon size={18} />
        </div>
      </div>
    </div>
  );
}

function Modal({ open, onClose, title, children, maxWidth = "max-w-md" }) {
  const bodyRef = useRef(null);

  useEffect(() => {
    if (open && bodyRef.current) bodyRef.current.scrollTop = 0;
  }, [open, children]);

  useEffect(() => {
    if (!open) return;
    const prevOverflow = document.body.style.overflow;
    document.body.style.overflow = "hidden";
    return () => { document.body.style.overflow = prevOverflow; };
  }, [open]);

  if (!open) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-start sm:items-center justify-center p-0 sm:p-4 overflow-y-auto overscroll-contain">
      <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm" onClick={onClose} />
      <div
        ref={bodyRef}
        className={`relative w-full ${maxWidth} max-h-[100dvh] sm:max-h-[88vh] overflow-y-auto overscroll-contain rounded-none sm:rounded-2xl bg-white shadow-xl border border-slate-200 animate-[fadeIn_.15s_ease-out] my-0 sm:my-8`}
      >
        <div className="sticky top-0 z-10 bg-white flex items-center justify-between px-5 py-4 border-b border-slate-100">
          <h3 className="font-semibold text-slate-900" style={{ fontFamily: "Sora, sans-serif" }}>{title}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 rounded-lg p-1">
            <X size={18} />
          </button>
        </div>
        <div className="p-5 pb-8">{children}</div>
      </div>
    </div>
  );
}

function Field({ label, ...props }) {
  return (
    <label className="block mb-3">
      <span className="block text-xs font-medium text-slate-600 mb-1">{label}</span>
      <input
        {...props}
        className="w-full rounded-lg border border-slate-200 px-3 py-2 text-sm text-slate-800 outline-none focus:ring-2 focus:ring-blue-400/40 focus:border-blue-400"
      />
    </label>
  );
}

